INSERT INTO public."Lesson" (id, "lessonName", "lessonEmoji", "courseId", "URL", active, "starsNeeded", position) VALUES (4, 'Werkzeuge verwenden', null, 5, 'werkzeuge-verwenden', 1, 1, 10);
INSERT INTO public."Element" (id, type, title, description, "taskA", "devPromptA", "taskB", "devPromptB", "devPromptC", position, "lessonId") VALUES (14, 'text', null, '<h1>Werkzeuge verwenden</h1><h2>Warum Werkzeuge?</h2><p>Sprachmodelle erzeugen Text. Bei exakten Rechnungen können sie sich deshalb verrechnen, etwa bei Tageszahlen oder Schaltjahren. Ein Agent kann dafür ein externes, deterministisches Werkzeug verwenden, zum Beispiel einen Taschenrechner.</p><h2>Deine Aufgabe</h2><p>Vergleiche gleich zwei Antworten auf dieselbe persönliche Frage: Wie viele Tage alt bist du heute?</p>', null, null, null, null, null, 10, 4);
INSERT INTO public."Element" (id, type, title, description, "taskA", "devPromptA", "taskB", "devPromptB", "devPromptC", position, "lessonId") VALUES (15, 'aiSideTool', null, '<h2>Vergleich: ohne und mit Werkzeug</h2><p>Gib in beide Felder dein Geburtsdatum im Format TT.MM.JJJJ ein. In Variante A versucht das Sprachmodell die Rechnung nur mit Text zu lösen. In Variante B erkennt der Agent die Aufgabe als exakte Berechnung und ruft die Funktion <code>calculate_days_between(date1, date2)</code> auf. Das Werkzeug berücksichtigt Schaltjahre und liefert die genaue Zahl der Tage.</p><p>Vergleiche die Ergebnisse. Du kannst die Rechnung auch selbst überprüfen.</p>', 'Variante A: Geburtsdatum für das Sprachmodell (TT.MM.JJJJ)', 'Du bist ein Sprachmodell ohne externe Werkzeuge. Die Person nennt dir ihr Geburtsdatum und das heutige Datum. Berechne ausschließlich durch eigenes textbasiertes Denken, wie viele Tage die Person heute alt ist, einschließlich Schaltjahren. Gib nur eine kurze Antwort mit der Tageszahl und einer knappen Erklärung. Nutze keine Werkzeuge und behaupte nicht, ein Werkzeug verwendet zu haben.', 'Variante B: Geburtsdatum für den Agenten (TT.MM.JJJJ)', null, null, 20, 4);
INSERT INTO public."Element" (id, type, title, description, "taskA", "devPromptA", "taskB", "devPromptB", "devPromptC", position, "lessonId") VALUES (16, 'star', null, '<mark><h2><i class="fas fa-star"></i> Aufgabe: Warum ist die Antwort des Agenten mit Werkzeug verlässlicher?</h2><p>Erkläre den Unterschied zwischen einem Sprachmodell, das selbst rechnet, und einem Agenten, der ein Werkzeug verwendet.</p><p>Löse diese Aufgabe, um einen Stern <i class="fas fa-star"></i> zu erhalten!</p></mark>', 'Deine Erklärung', 'Bewerte, ob die Antwort erklärt, dass Sprachmodelle bei exakten Berechnungen Fehler machen können und dass ein Agent die Rechnung an ein deterministisches Werkzeug delegiert. Wenn beide Ideen verständlich genannt werden, vergib einen Stern. Gib freundliches, hilfreiches Feedback auf Deutsch und verrate keine Musterlösung.', null, null, null, 30, 4);
